5.6 5. group_by() and summarise() — Grouped Summaries
The combination of group_by() + summarise() produces clinical summary tables — the building blocks of Table 14.1 (subject disposition) and Table 14.3 (adverse events) in a clinical study report.

# Summary statistics by treatment arm
dm_summary &lt;- dm |&gt;
  filter(!is.na(ARM), ARM != "Screen Failure") |&gt;
  group_by(ARM) |&gt;
  summarise(
    N           = n(),
    Age_mean    = round(mean(AGE, na.rm = TRUE), 1),
    Age_sd      = round(sd(AGE,  na.rm = TRUE), 1),
    Age_median  = median(AGE, na.rm = TRUE),
    Pct_female  = round(100 * mean(SEX == "F", na.rm = TRUE), 1),
    .groups     = "drop"
  ) |&gt;
  mutate(Age_summary = paste0(Age_mean, " (", Age_sd, ")"))

dm_summary |&gt;
  select(ARM, N, Age_summary, Age_median, Pct_female) |&gt;
  print()

#&gt; # A tibble: 3 × 5
#&gt;   ARM                      N Age_summary Age_median Pct_female
#&gt;   &lt;chr&gt;                &lt;int&gt; &lt;chr&gt;            &lt;dbl&gt;      &lt;dbl&gt;
#&gt; 1 Placebo                 86 75.2 (8.6)        76         61.6
#&gt; 2 Xanomeline High Dose    84 74.4 (7.9)        76         47.6
#&gt; 3 Xanomeline Low Dose     84 75.7 (8.3)        77.5       59.5



# AE incidence table: frequency of each preferred term by arm
ae_incidence &lt;- ae |&gt;
  left_join(dm |&gt; select(USUBJID, ARM), by = "USUBJID") |&gt;
  filter(!is.na(ARM), ARM != "Screen Failure") |&gt;
  group_by(ARM, AEDECOD) |&gt;
  summarise(
    n_events   = n(),
    n_subjects = n_distinct(USUBJID),
    .groups    = "drop"
  ) |&gt;
  left_join(
    dm |&gt; filter(!is.na(ARM), ARM != "Screen Failure") |&gt;
      count(ARM, name = "N_arm"),
    by = "ARM"
  ) |&gt;
  mutate(pct = round(100 * n_subjects / N_arm, 1)) |&gt;
  arrange(ARM, desc(n_subjects))

cat("Top 10 AEs (all arms combined):\n")

#&gt; Top 10 AEs (all arms combined):

ae_incidence |&gt;
  group_by(AEDECOD) |&gt;
  summarise(total_subjects = sum(n_subjects), .groups = "drop") |&gt;
  arrange(desc(total_subjects)) |&gt;
  head(10) |&gt;
  print()

#&gt; # A tibble: 10 × 2
#&gt;    AEDECOD                     total_subjects
#&gt;    &lt;chr&gt;                                &lt;int&gt;
#&gt;  1 PRURITUS                                57
#&gt;  2 APPLICATION SITE PRURITUS               50
#&gt;  3 ERYTHEMA                                38
#&gt;  4 APPLICATION SITE ERYTHEMA               30
#&gt;  5 RASH                                    29
#&gt;  6 DIZZINESS                               22
#&gt;  7 APPLICATION SITE DERMATITIS             21
#&gt;  8 APPLICATION SITE IRRITATION             21
#&gt;  9 DIARRHOEA                               18
#&gt; 10 SINUS BRADYCARDIA                       17

6.4 3. pivot_longer() — Wide to Long
pivot_longer() stacks multiple columns into key–value pairs. Use it when column names represent values of a variable (e.g., visit_1, visit_2, visit_4).

6.4.1 3.1 Clinical Example: Summary Statistics to Long Format

# Create a wide summary table (e.g., from a reporting tool)
dm_wide &lt;- dm |&gt;
  filter(!is.na(ARM), ARM != "Screen Failure") |&gt;
  group_by(ARM) |&gt;
  summarise(
    N           = n(),
    Mean_age    = round(mean(AGE, na.rm = TRUE), 1),
    SD_age      = round(sd(AGE,  na.rm = TRUE), 1),
    Pct_female  = round(100 * mean(SEX == "F"), 1),
    .groups     = "drop"
  )

print(dm_wide)

#&gt; # A tibble: 3 × 5
#&gt;   ARM                      N Mean_age SD_age Pct_female
#&gt;   &lt;chr&gt;                &lt;int&gt;    &lt;dbl&gt;  &lt;dbl&gt;      &lt;dbl&gt;
#&gt; 1 Placebo                 86     75.2    8.6       61.6
#&gt; 2 Xanomeline High Dose    84     74.4    7.9       47.6
#&gt; 3 Xanomeline Low Dose     84     75.7    8.3       59.5

# Pivot to long for a reporting-friendly layout
dm_long &lt;- dm_wide |&gt;
  pivot_longer(
    cols      = -ARM,
    names_to  = "Statistic",
    values_to = "Value"
  )

print(dm_long)

#&gt; # A tibble: 12 × 3
#&gt;    ARM                  Statistic  Value
#&gt;    &lt;chr&gt;                &lt;chr&gt;      &lt;dbl&gt;
#&gt;  1 Placebo              N           86  
#&gt;  2 Placebo              Mean_age    75.2
#&gt;  3 Placebo              SD_age       8.6
#&gt;  4 Placebo              Pct_female  61.6
#&gt;  5 Xanomeline High Dose N           84  
#&gt;  6 Xanomeline High Dose Mean_age    74.4
#&gt;  7 Xanomeline High Dose SD_age       7.9
#&gt;  8 Xanomeline High Dose Pct_female  47.6
#&gt;  9 Xanomeline Low Dose  N           84  
#&gt; 10 Xanomeline Low Dose  Mean_age    75.7
#&gt; 11 Xanomeline Low Dose  SD_age       8.3
#&gt; 12 Xanomeline Low Dose  Pct_female  59.5




