8.8 6.7 Publication-Ready Tables with gtsummary
The gtsummary package creates FDA-submission-quality tables with minimal code.

# Install if needed: install.packages("gtsummary")
library(gtsummary)

# Load data
data(dm)
data(vs)
data(lb)

# Merge demographics with baseline vitals and labs
baseline_data &lt;- dm %&gt;%
  left_join(
    vs %&gt;%
      filter(VSTESTCD == "SYSBP", VISITNUM == 1) %&gt;%
      select(USUBJID, VSSTRESN) %&gt;%
      mutate(VSSTRESN = as.numeric(VSSTRESN)) %&gt;%
      rename(SBP_Baseline = VSSTRESN),
    by = "USUBJID"
  ) %&gt;%
  left_join(
    lb %&gt;%
      filter(LBTESTCD == "CREAT", !is.na(LBSTRESN)) %&gt;%
      group_by(USUBJID) %&gt;%
      slice_min(VISITNUM, n = 1, with_ties = FALSE) %&gt;%
      ungroup() %&gt;%
      select(USUBJID, LBSTRESN) %&gt;%
      rename(CREATININE = LBSTRESN),
    by = "USUBJID"
  ) %&gt;%
  mutate(
    # Convert age to categorical for table
    AGE_GR = case_when(
      AGE &lt; 40 ~ "&lt;40",
      AGE &gt;= 40 & AGE &lt; 65 ~ "40-64",
      AGE &gt;= 65 ~ "&gt;=65"
    )
  ) %&gt;%
  select(ARM, AGE, AGE_GR, SEX, RACE, SBP_Baseline, CREATININE)

# Create baseline characteristics table
baseline_table &lt;- baseline_data %&gt;%
  tbl_summary(
    by = ARM,  # Stratify by treatment arm
    statistic = list(
      all_continuous() ~ "{mean} ({sd})",  # Mean (SD) for continuous
      all_categorical() ~ "{n} ({p}%)"  # N (%) for categorical
    ),
    digits = list(
      all_continuous() ~ 1,
      all_categorical() ~ 0
    ),
    label = list(
      AGE ~ "Age (years)",
      SEX ~ "Sex",
      RACE ~ "Race",
      SBP_Baseline ~ "Baseline Systolic BP (mmHg)",
      CREATININE ~ "Baseline Creatinine (mg/dL)"
    )
  ) %&gt;%
  # Add overall column
  add_overall() %&gt;%
  # Add p-values for comparison
  add_p() %&gt;%
  # Modify header
  modify_header(label ~ "**Characteristic**") %&gt;%
  # Convert to standard table format for display
  as_gt()

print(baseline_table)

