# Example: Summary by treatment arm with custom statistics
baseline_data %&gt;%
  select(ARM, AGE, SBP_Baseline, CREATININE) %&gt;%
  tbl_summary(
    by = ARM,
    statistic = list(
      AGE ~ "{median} ({p25}, {p75})",  # Median and IQR
      SBP_Baseline ~ "{mean} ± {sd}",   # Mean ± SD
      CREATININE ~ "{min}-{max}"        # Range
    ),
    missing = "no"  # Don't show missing counts
  ) %&gt;%
  add_overall() %&gt;%
  as_gt()















