8.9 6.8 Complete EDA Workflow: Hypertension Trial
Here’s a comprehensive EDA for our hypertension trial example:

# ============================================
# COMPLETE EDA WORKFLOW
# Hypertension Trial - Baseline Analysis
# ============================================

library(pharmaversesdtm)
library(dplyr)
library(tidyr)
library(gtsummary)

# Load SDTM domains
data(dm)
data(vs)
data(lb)
data(ae)

# ========== STEP 1: DEMOGRAPHIC SUMMARY ==========
cat("=== DEMOGRAPHIC SUMMARY ===\n\n")

#&gt; === DEMOGRAPHIC SUMMARY ===

demo_summary &lt;- dm %&gt;%
  select(ARM, AGE, SEX, RACE, ETHNIC) %&gt;%
  tbl_summary(
    by = ARM,
    statistic = list(
      AGE ~ "{mean} ({sd})",
      all_categorical() ~ "{n} ({p}%)"
    ),
    digits = list(AGE ~ 1, everything() ~ 0),
    missing = "no"
  ) %&gt;%
  add_overall() %&gt;%
  add_p()

print(demo_summary)

