# ========== STEP 2: BASELINE VITALS ==========
cat("\n=== BASELINE VITALS BY ARM ===\n\n")

#&gt; 
#&gt; === BASELINE VITALS BY ARM ===

baseline_vitals &lt;- vs %&gt;%
  filter(VISITNUM == 1, VSTESTCD %in% c("SYSBP", "DIABP", "PULSE"),
         !is.na(VSSTRESN)) %&gt;%
  select(USUBJID, VSTESTCD, VSSTRESN) %&gt;%
  mutate(VSSTRESN = as.numeric(VSSTRESN)) %&gt;%
  # Average if multiple records per subject × parameter (avoids list columns)
  group_by(USUBJID, VSTESTCD) %&gt;%
  summarise(VSSTRESN = mean(VSSTRESN, na.rm = TRUE), .groups = "drop") %&gt;%
  pivot_wider(
    names_from  = VSTESTCD,
    values_from = VSSTRESN
  ) %&gt;%
  left_join(dm %&gt;% select(USUBJID, ARM), by = "USUBJID") %&gt;%
  select(ARM, any_of(c("SYSBP", "DIABP", "PULSE")))

baseline_vitals %&gt;%
  tbl_summary(
    by = ARM,
    statistic = list(
      all_continuous() ~ "{mean} ({sd}) [{min}-{max}]"
    ),
    digits = list(all_continuous() ~ 1),
    label = list(
      SYSBP ~ "Systolic BP (mmHg)",
      DIABP ~ "Diastolic BP (mmHg)",
      PULSE ~ "Heart Rate (bpm)"
    ),
    missing = "no"
  ) %&gt;%
  add_overall() %&gt;%
  add_p()















