# ========== STEP 3: DISTRIBUTION CHECKS ==========
cat("\n=== NORMALITY TESTS (SHAPIRO-WILK) ===\n\n")

#&gt; 
#&gt; === NORMALITY TESTS (SHAPIRO-WILK) ===

sbp_by_arm &lt;- vs %&gt;%
  filter(VISITNUM == 1, VSTESTCD == "SYSBP") %&gt;%
  select(USUBJID, VSSTRESN) %&gt;%
  mutate(VSSTRESN = as.numeric(VSSTRESN)) %&gt;%
  left_join(dm %&gt;% select(USUBJID, ARM), by = "USUBJID")

for (arm in unique(sbp_by_arm$ARM)) {
  sbp_values &lt;- sbp_by_arm %&gt;%
    filter(ARM == arm) %&gt;%
    pull(VSSTRESN)

  test &lt;- shapiro.test(sbp_values)
  cat(sprintf("%s: W = %.4f, p-value = %.4f\n",
              arm, test$statistic, test$p.value))
}

