# ========== STEP 4: OUTLIER DETECTION ==========
cat("\n=== OUTLIER DETECTION (IQR METHOD) ===\n\n")

#&gt; 
#&gt; === OUTLIER DETECTION (IQR METHOD) ===

sbp_all &lt;- vs %&gt;%
  filter(VISITNUM == 1, VSTESTCD == "SYSBP") %&gt;%
  pull(VSSTRESN) %&gt;%
  as.numeric()

Q1 &lt;- quantile(sbp_all, 0.25, na.rm = TRUE)
Q3 &lt;- quantile(sbp_all, 0.75, na.rm = TRUE)
IQR_val &lt;- Q3 - Q1
lower_fence &lt;- Q1 - 1.5 * IQR_val
upper_fence &lt;- Q3 + 1.5 * IQR_val

outlier_count &lt;- sum(sbp_all &lt; lower_fence | sbp_all &gt; upper_fence, na.rm = TRUE)
cat(sprintf("Fences: [%.1f, %.1f]\n", lower_fence, upper_fence))

